UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Pootaardappel, Consumptieaardappel, Zetmeelaardappel", "doelorganisme": "Coloradokever", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "2.5 L/ha", "maxToepassingen": 2, "veiligheidstermijn": "4 dagen", "interval": "min. 7 dagen", "opmerkingen": ["Geclaimd organisme: Coloradokever (Leptinotarsa decemlineata), larvale stadia 1-3\n\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden\nafgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen.", {"sentenceNL": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie in grondwaterbeschermingsgebieden in de periode 01/sep. tot 01/mrt.. De betreffende restrictiezin op het WG luidt: Om het grondwater te beschermen mag dit middel in de onbedekte teelt van aardappelen, druiven, steenvruchten, bessen, braam- en framboosachtigen, spinazie-achtigen, vruchtgroenten van Cucurbitaceae met eetbare schil, ui-achtigen (m.u.v. zaaiui), prei, en aromatische kruidgewassen (m.u.v. bieslook) niet worden gebruikt in grondwaterbeschermingsgebieden van 1 september tot 1 maart..", "sentenceEN": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie in grondwaterbeschermingsgebieden in de periode 01/sep. tot 01/mrt.. De betreffende restrictiezin op het WG luidt: Om het grondwater te beschermen mag dit middel in de onbedekte teelt van aardappelen, druiven, steenvruchten, bessen, braam- en framboosachtigen, spinazie-achtigen, vruchtgroenten van Cucurbitaceae met eetbare schil, ui-achtigen (m.u.v. zaaiui), prei, en aromatische kruidgewassen (m.u.v. bieslook) niet worden gebruikt in grondwaterbeschermingsgebieden van 1 september tot 1 maart..", "orgSentenceNL": "Om het grondwater te beschermen geldt er voor deze toepassing een restrictie {locatie} in de periode {start} tot {ein