UPDATE ctgb_products SET gebruiksvoorschriften = '[{"gewas": "Wintertarwe, Triticale, Zomertarwe", "doelorganisme": "Oogvlekkenziekte, Voetziekte", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "1.5 L/ha", "maxToepassingen": 1, "veiligheidstermijn": "35 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n\nToepassingsvoorwaarde: \nIn de teelt van zomer- en wintertarwe, triticale, zomer- en wintergerst bij twee keer toepassen, het middel toepassen vanaf tweede knoop ten minste 2 cm boven de eerste knoop (BBCH 32) tot en met midden van aarvorming: helft van bloeiwijze uitgekomen (BBCH 55). \n\nIn de teelt van zomer- en wintertarwe, triticale bij 1 keer toepassen het middel toepassen vanaf tweede knoop ten minste 2 cm boven de eerste knoop (BBCH 32) tot en met het einde van de bloei: alle aartjes uitgebloeid (BBCH 69).\n\nVerlaging van de dosering is toegestaan, maar van het maximaal aantal toepassingen en de andere toepassingsvoorwaarden mag niet worden afgeweken. Werkzaamheid is vastgesteld voor de genoemde dosering per toepassing en niet voor verlaagde doseringen."], "wCodes": ["W6"], "bbchVan": "32", "bbchTot": "32", "seizoenVan": 4, "seizoenTot": 4, "spuitvolumeMin": 200, "spuitvolumeMax": 400, "phiDagen": 35}, {"gewas": "Wintertarwe, Triticale, Zomertarwe", "doelorganisme": "Bladvlekkenziekte, Echte meeldauw, Meeldauw, Gele bladvlekkenziekte, Netvlekkenziekte, Bruine roest, Roest, Gele roest", "locatie": "Onbedekt", "toepassingsmethode": "Gewasbehandeling", "dosering": "1.5 L/ha", "maxToepassingen": 2, "veiligheidstermijn": "35 dagen", "opmerkingen": ["De gegevens van dit gebruik zijn gebaseerd op het wettelijk gebruiksvoorschrift dat geldig is vanaf 01-01-2019. Raadpleeg voor de complete informatie altijd het wettelijk gebruiksvoorschrift en het etiket.\n